/**
 * 메뉴가 펼쳐질 경우, 호출될 callback 함수
 * @callback onActivate
 *
 * @param {event} e - 이벤트 객체
 * @param {object} ui - 생성된 엘리먼트 집합
 *
 * @memberOf BxAccordion
 */

/**
 * 메뉴 선택 시, 호출될 callback 함수
 * @callback onSelected
 *
 * @param {event} e - 이벤트 객체
 * @param {object} ui - 생성된 엘리먼트 집합
 *
 * @memberOf BxAccordion
 */

/**
 * 랜더링 완료 시, 호출될 callback 함수
 *
 * @callback onRender
 *
 * @param {event} e - 이벤트 객체
 * @param {object} ui - 생성된 엘리먼트 집합
 *
 * @memberOf BxAccordion
 */

