/**
 * 선택된 item id 반환 함수
 *
 * @returns {string} id
 * @private
 */
function _getSelectedId(){

    let $item = this.$container.find('.selected').parent();
    let id = $item.attr('id');

    if (_.isEmpty(id)) id = '';

    return id;
}


